class Solution:
    def minLength(self, s):
        while True:
            if 'AB' in s:
                idx = s.index('AB')
                s = s[:idx] + s[idx + 2:]
            elif 'CD' in s:
                idx = s.index('CD')
                s = s[:idx] + s[idx + 2:]
            else:
                break
        return len(s)

