var minLength = function(s) {
    const stack = [];
    for (const ch of s) {
        const top = stack[stack.length - 1];
        if (top !== undefined && ((top === 'A' && ch === 'B') || (top === 'C' && ch === 'D'))) {
            stack.pop();
        } else {
            stack.push(ch);
        }
    }
    return stack.length;
};
